    results.push({ check: 'Owner-only auth', http: 0, expected: '401+200', actual: 'FAIL: ' + e.message, timestamp: now() });
    console.log('FAIL:', e.message);
  }

  // === SUMMARY ===
  console.log('\\n\\n========== PHASE 1 SUMMARY ==========');
  const pass = results.filter(r => r.actual.startsWith('PASS')).length;
  const fail = results.filter(r => r.actual.startsWith('FAIL')).length;
  results.forEach(r => {
    console.log(r.check + ': ' + r.actual + ' (HTTP ' + r.http + ') @ ' + r.timestamp);
  });
  console.log('\\nTotal: ' + results.length + ' | PASS: ' + pass + ' | FAIL: ' + fail);

  // Write evidence
  const evidence = {
    title: 'Phase 1 — Production Claims Re-Verification',
    timestamp: now(),
    checks: results,
    totalChecks: results.length,
    passed: pass,
    failed: fail,
    blocked: results.filter(r => r.actual.includes('BLOCKED')).length,
    notVerified: results.filter(r => r.actual.includes('NOT VERIFIED')).length
  };
  require('fs').writeFileSync('/tmp/phase1-results.json', JSON.stringify(evidence, null, 2));
  console.log('\\nEvidence written to /tmp/phase1-results.json');
}
main().catch(e => console.error('FATAL:', e.message));
