    console.log('No-auth HTTP:', r1.status);
    // Test that it accepts owner-authenticated requests
    const r2 = await fetch('https://api.ivxholding.com/api/ivx/agent-audit/overview', {
      headers: { Authorization: 'Bearer ' + token },
    });
    const j2 = await r2.json();
    console.log('Owner-auth HTTP:', r2.status);
