   430|function computeScorePercentage(assessments: CapabilityAssessment[]): number {
   431|  const weights: Record<CapabilityScore, number> = { PASS: 1, PARTIAL: 0.5, FAIL: 0, NOT_CONFIGURED: 0 };
   432|  const total = assessments.reduce((sum, a) => sum + weights[a.score], 0);
   433|  return Math.round((total / assessments.length) * 100);
   434|}
