   436|function classifySeniority(score: number): SeniorityLevel {
   437|  if (score >= 85) return 'SENIOR';
   438|  if (score >= 65) return 'MID';
   439|  if (score >= 40) return 'JUNIOR';
   440|  return 'NOT_A_DEVELOPER';
