   443|function deriveMainGap(agentId: ExecutiveAgentId, assessments: CapabilityAssessment[]): string {
   444|  const fails = assessments.filter((a) => a.score === 'FAIL');
   445|  const partials = assessments.filter((a) => a.score === 'PARTIAL');
   446|  if (fails.length > 10) return 'Agent is analysis-only — cannot write code, run tests, or deploy. Needs code_patch_proposal + run_tests tools to become a developer agent';
   447|  if (fails.length > 5) return `Missing ${fails.length} capabilities: ${fails.slice(0, 3).map((f) => f.capability).join(', ')}`;
   448|  if (partials.length > 5) return `Partial on ${partials.length} capabilities — needs full tool access for autonomous execution`;
   449|  return 'Minor gaps — mostly needs autonomous execution permission and Git commit tools';
   450|}
